{"content":"package com.pinterest.ktlint.rule.engine.internal.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleId
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
import org.jetbrains.kotlin.psi.KtAnnotationEntry
import org.jetbrains.kotlin.psi.KtLiteralStringTemplateEntry
import org.jetbrains.kotlin.psi.KtStringTemplateExpression
import org.jetbrains.kotlin.psi.psiUtil.startOffset

internal class KtlintSuppressionRule : InternalRule("ktlint:suppression") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.psi is PsiComment) {
            visitComment(node, autoCorrect, emit)
        }
        if (node.psi is KtAnnotationEntry) {
            visitAnnotationEntry(node, autoCorrect, emit)
        }
    }

    private fun visitComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text = node.text
        if (text.contains("experimental:")) {
            emit(node.startOffset, "Replace 'experimental' with 'standard' in ktlint directive", true)
            if (autoCorrect) {
                (node as LeafPsiElement).replaceWithText(text.replace("experimental:", "standard:"))
            }
        }
        if (node.text.contains("ktlint-disable") || node.text.contains("ktlint-enable")) {
            emit(node.startOffset, "Directive 'ktlint-disable/ktlint-enable' is deprecated. Use @Suppress instead.", false)
        }
    }

    private fun visitAnnotationEntry(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val annotationEntry = node.psi as KtAnnotationEntry
        annotationEntry.valueArguments.forEach { argument ->
            val expression = argument.getArgumentExpression()
            if (expression is KtStringTemplateExpression) {
                val entries = expression.entries
                if (entries.size == 1 && entries[0] is KtLiteralStringTemplateEntry) {
                    val value = entries[0].text
                    if (value.contains("experimental:")) {
                        emit(argument.asElement().startOffset, "Replace 'experimental' with 'standard' in suppression", true)
                        if (autoCorrect) {
                            val entryNode = entries[0].node
                            (entryNode as LeafPsiElement).replaceWithText(value.replace("experimental:", "standard:"))
                        }
                    }
                }
            }
        }
    }

    companion object {
        val KTLINT_SUPPRESSION_RULE_ID = RuleId("ktlint:suppression")
    }
}
