import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.api.LintError
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

class KtlintSuppressionRuleTest {
    @Test
    fun `Given ktlint-disable directive then report a violation`() {
        val code = """
            val foo = "foo" // ktlint-disable
        """.trimIndent()

        val errors = lint(code)
        assertThat(errors).hasSize(1)
        assertThat(errors[0].ruleId.value).isEqualTo("ktlint:suppression")
        assertThat(errors[0].detail).contains("deprecated")
    }

    @Test
    fun `Given ktlint-enable directive then report a violation`() {
        val code = """
            /* ktlint-enable */
        """.trimIndent()

        val errors = lint(code)
        assertThat(errors).hasSize(1)
        assertThat(errors[0].ruleId.value).isEqualTo("ktlint:suppression")
    }

    @Test
    fun `Given experimental rule set reference in comment then replace with standard`() {
        val code = """
            /* ktlint-disable experimental:foo */
        """.trimIndent()

        val formatted = format(code)
        assertThat(formatted).isEqualTo("""
            /* ktlint-disable standard:foo */
        """.trimIndent())
    }

    @Test
    fun `Given experimental rule set reference in suppress annotation then replace with standard`() {
        val code = """
            @Suppress("ktlint:experimental:foo")
            val foo = "foo"
        """.trimIndent()

        val formatted = format(code)
        assertThat(formatted).isEqualTo("""
            @Suppress("ktlint:standard:foo")
            val foo = "foo"
        """.trimIndent())
    }

    private fun lint(code: String): List<LintError> {
        val errors = ArrayList<LintError>()
        KtLintRuleEngine(
            ruleProviders = setOf(RuleProvider { DummyRule() }),
        ).lint(Code.fromSnippet(code)) { e -> errors.add(e) }
        return errors
    }

    private fun format(code: String): String =
        KtLintRuleEngine(
            ruleProviders = setOf(RuleProvider { DummyRule() }),
        ).format(Code.fromSnippet(code))

    private class DummyRule : Rule(RuleId("standard:dummy"), About()) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {}
    }
}
